local function ResolveIcon(name)
	if not name or name == "" then
		return ""
	end

	if typeof(name) == "number" then
		return "rbxassetid://" .. tostring(name)
	end

	if name:sub(1, 12) == "rbxassetid:/" then
		return name
	end

	if name:match("^%d+$") then
		return "rbxassetid://" .. name
	end

	local urlId = name:match("[?&]id=(%d+)") or name:match("/(%d+)/?$")
	if urlId and (name:find("roblox.com") or name:find("rbxassetid")) then
		return "rbxassetid://" .. urlId
	end

	local key = name
	if key:sub(1, 11) ~= "FrontEvill-" then
		key = "FrontEvill-" .. key
	end

	return Icons[key] or Icons["FrontEvill-circle"]
end

return {
	Icons = Icons,
	ResolveIcon = ResolveIcon,
}
end)()

_modules["Keybinds"] = (function()
local function ResolveKeybind(name)
	if not name or name == "" then
		return nil, nil
	end

	if name == "MB1" then
		return Enum.UserInputType.MouseButton1, "MouseButton"
	end

	if name == "MB2" then
		return Enum.UserInputType.MouseButton2, "MouseButton"
	end

	if name == "MB3" then
		return Enum.UserInputType.MouseButton3, "MouseButton"
	end

	local ok, keycode = pcall(function()
		return Enum.KeyCode[name]
	end)

	if ok and keycode then
		return keycode, "KeyCode"
	end

	return nil, nil
end

local function KeybindDisplayName(boundValue, boundType)
	if not boundValue then
		return "None"
	end

	if boundType == "MouseButton" then
		if boundValue == Enum.UserInputType.MouseButton1 then
			return "MB1"
		elseif boundValue == Enum.UserInputType.MouseButton2 then
			return "MB2"
		elseif boundValue == Enum.UserInputType.MouseButton3 then
			return "MB3"
		end
	end

	return boundValue.Name
end

return {
	ResolveKeybind = ResolveKeybind,
	KeybindDisplayName = KeybindDisplayName,
}
end)()

_modules["Theme"] = (function()
local function ToColor3(value)
	if typeof(value) == "Color3" then
		return value
	end

	if typeof(value) == "string" then
		local hex = value:gsub("#", "")
		if #hex == 3 then
			local r = hex:sub(1, 1)
			local g = hex:sub(2, 2)
			local b = hex:sub(3, 3)
			hex = r .. r .. g .. g .. b .. b
		end
		local r = tonumber(hex:sub(1, 2), 16) or 255
		local g = tonumber(hex:sub(3, 4), 16) or 255
		local b = tonumber(hex:sub(5, 6), 16) or 255
		return Color3.fromRGB(r, g, b)
	end

	if typeof(value) == "table" then
		if value.R and value.G and value.B then
			return Color3.fromRGB(value.R, value.G, value.B)
		end
		if value[1] and value[2] and value[3] then
			return Color3.fromRGB(value[1], value[2], value[3])
		end
	end

	return Color3.fromRGB(255, 255, 255)
end

local function ResolveTheme(theme)
	local resolved = {}
	for key, value in pairs(theme) do
		if key == "Transparency" then
			resolved[key] = value
		else
			resolved[key] = ToColor3(value)
		end
	end
	return resolved
end

local function GenerateThemeFromAccent(accent)
	local h, s = accent:ToHSV()

	local background = Color3.fromHSV(h, math.clamp(s * 0.35, 0, 0.35), 0.085)
	local secondary = Color3.fromHSV(h, math.clamp(s * 0.35, 0, 0.35), 0.125)
	local descColor = Color3.fromHSV(h, math.clamp(s * 0.25, 0, 0.25), 0.68)

	return {
		Accent = accent,
		Background = background,
		Secondary = secondary,
		TitleColor = Color3.fromRGB(255, 255, 255),
		DescColor = descColor,
		SectionColor = accent,
		Transparency = 0.35,
	}
end

local Presets = {
	Dark = GenerateThemeFromAccent(Color3.fromRGB(130, 130, 140)),
	Purple = GenerateThemeFromAccent(Color3.fromRGB(150, 100, 255)),
	Rose = GenerateThemeFromAccent(Color3.fromRGB(255, 90, 130)),
	Blue = GenerateThemeFromAccent(Color3.fromRGB(80, 140, 255)),
	Green = GenerateThemeFromAccent(Color3.fromRGB(80, 220, 150)),
	Orange = GenerateThemeFromAccent(Color3.fromRGB(255, 150, 70)),
	Cyan = GenerateThemeFromAccent(Color3.fromRGB(70, 220, 220)),
	Gold = GenerateThemeFromAccent(Color3.fromRGB(230, 190, 90)),
}

Presets.Dark.SectionColor = Color3.fromRGB(255, 255, 255)


local function GetRandomPresetName()
	local names = {}
	for name in pairs(Presets) do
		table.insert(names, name)
	end
	return names[math.random(1, #names)]
end


return {
	ToColor3 = ToColor3,
	ResolveTheme = ResolveTheme,
	GenerateThemeFromAccent = GenerateThemeFromAccent,
	Presets = Presets,
	GetRandomPresetName = GetRandomPresetName,
}
end)()

_modules["Utils"] = (function()
local Players = game:GetService("Players")
local UserInputService = game:GetService("UserInputService")
local TweenService = game:GetService("TweenService")

local LocalPlayer = Players.LocalPlayer
local PlayerGui = LocalPlayer:WaitForChild("PlayerGui")

local function CreateInstance(className, properties)
	local inst = Instance.new(className)
	for prop, value in pairs(properties) do
		inst[prop] = value
	end
	return inst
end

local function MakeDraggable(dragHandle, target)
	local dragging = false
	local dragStart
	local startPos

	dragHandle.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
			dragging = true
			dragStart = input.Position
			startPos = target.Position

			input.Changed:Connect(function()
				if input.UserInputState == Enum.UserInputState.End then
					dragging = false
				end
			end)
		end
	end)

	UserInputService.InputChanged:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch then
			if dragging then
				local delta = input.Position - dragStart
				target.Position = UDim2.new(
					startPos.X.Scale,
					startPos.X.Offset + delta.X,
					startPos.Y.Scale,
					startPos.Y.Offset + delta.Y
				)
			end
		end
	end)
end

local function AttachTooltip(window, target, text)
	if not text or text == "" then
		return
	end

	local tooltipLabel
	local moveConnection

	local function updatePosition(pos)
		if tooltipLabel then
			tooltipLabel.Position = UDim2.new(0, pos.X + 16, 0, pos.Y + 16)
		end
	end

	target.MouseEnter:Connect(function()
		window.TooltipGui = window.TooltipGui or CreateInstance("ScreenGui", {
			Name = "VantaTooltip",
			Parent = PlayerGui,
			ResetOnSpawn = false,
			ZIndexBehavior = Enum.ZIndexBehavior.Sibling,
			DisplayOrder = 3000,
			IgnoreGuiInset = true,
		})

		tooltipLabel = CreateInstance("TextLabel", {
			Name = "Tooltip",
			Parent = window.TooltipGui,
			AutomaticSize = Enum.AutomaticSize.XY,
			BackgroundColor3 = window.Theme.Background,
			BackgroundTransparency = 0.05,
			Text = text,
			Font = Enum.Font.Gotham,
			TextSize = 12,
			TextColor3 = window.Theme.TitleColor,
			TextWrapped = true,
			ZIndex = 100,
		})

		CreateInstance("UICorner", {
			Parent = tooltipLabel,
			CornerRadius = UDim.new(0, 6),
		})

		CreateInstance("UIStroke", {
			Parent = tooltipLabel,
			Color = window.Theme.Accent,
			Thickness = 1,
			Transparency = 0.3,
		})

		CreateInstance("UIPadding", {
			Parent = tooltipLabel,
			PaddingTop = UDim.new(0, 4),
			PaddingBottom = UDim.new(0, 4),
			PaddingLeft = UDim.new(0, 8),
			PaddingRight = UDim.new(0, 8),
		})

		local ok, mouseLoc = pcall(function()
			return UserInputService:GetMouseLocation()
		end)
		if ok and mouseLoc then
			updatePosition(mouseLoc)
		end

		moveConnection = UserInputService.InputChanged:Connect(function(input)
			if input.UserInputType == Enum.UserInputType.MouseMovement then
				updatePosition(input.Position)
			end
		end)
	end)

	target.MouseLeave:Connect(function()
		if moveConnection then
			moveConnection:Disconnect()
			moveConnection = nil
		end
		if tooltipLabel then
			tooltipLabel:Destroy()
			tooltipLabel = nil
		end
	end)
end

local function FadeTransparency(entries, duration, easingDirection)
	for _, entry in ipairs(entries) do
		local tween = TweenService:Create(
			entry.instance,
			TweenInfo.new(duration, Enum.EasingStyle.Quad, easingDirection),
			{ [entry.prop] = entry.target }
		)
		tween:Play()
	end
end

local function MakeResizable(handle, target, minSize, maxSize)
	local resizing = false
	local dragStart
	local startSize

	handle.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
			resizing = true
			dragStart = input.Position
			startSize = target.Size

			input.Changed:Connect(function()
				if input.UserInputState == Enum.UserInputState.End then
					resizing = false
				end
			end)
		end
	end)

	UserInputService.InputChanged:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch then
			if resizing then
				local delta = input.Position - dragStart
				local newWidth = math.clamp(startSize.X.Offset + delta.X, minSize.X, maxSize.X)
				local newHeight = math.clamp(startSize.Y.Offset + delta.Y, minSize.Y, maxSize.Y)
				target.Size = UDim2.new(0, newWidth, 0, newHeight)
			end
		end
	end)
end


return {
	CreateInstance = CreateInstance,
	MakeDraggable = MakeDraggable,
	AttachTooltip = AttachTooltip,
	FadeTransparency = FadeTransparency,
	MakeResizable = MakeResizable,
}
end)()

_modules["Acrylic"] = (function()
local Lighting = game:GetService("Lighting")
local Workspace = game:GetService("Workspace")
local RunService = game:GetService("RunService")

local Utils = _require("Utils")
local CreateInstance = Utils.CreateInstance

local ActiveAcrylicCount = 0

local function EnableAcrylicLighting()
	ActiveAcrylicCount = ActiveAcrylicCount + 1

	local existing = Lighting:FindFirstChild("VantaAcrylicDOF")
	if existing then
		return
	end

	local dof = Instance.new("DepthOfFieldEffect")
	dof.Name = "VantaAcrylicDOF"
	dof.FarIntensity = 1
	dof.NearIntensity = 1
	dof.InFocusRadius = 0.05
	dof.FocusDistance = 0.05
	dof.Parent = Lighting
end

local function DisableAcrylicLighting()
	ActiveAcrylicCount = math.max(0, ActiveAcrylicCount - 1)

	if ActiveAcrylicCount == 0 then
		local existing = Lighting:FindFirstChild("VantaAcrylicDOF")
		if existing then
			existing:Destroy()
		end
	end
end

local function CreateGlassPart()
	local part = Instance.new("Part")
	part.Name = "VantaGlass"
	part.Anchored = true
	part.CanCollide = false
	part.CanQuery = false
	part.CastShadow = false
	part.Locked = true
	part.Material = Enum.Material.SmoothPlastic
	part.Reflectance = 0
	part.Color = Color3.new(0, 0, 0)
	part.Transparency = 0.98
	part.Size = Vector3.new(1, 1, 0)

	local mesh = Instance.new("SpecialMesh")
	mesh.MeshType = Enum.MeshType.Brick
	mesh.Offset = Vector3.new(0, 0, -0.0001)
	mesh.Parent = part

	return part, mesh
end

local function AttachAcrylicGlass(frame, screenGui)
	local camera = Workspace.CurrentCamera
	if not camera then
		return nil
	end

	local part, mesh = CreateGlassPart()
	part.Parent = camera

	local distance = 0.05
	local inset = 3
	local connections = {}
	local running = true

	local function project(point2D)
		local cam = Workspace.CurrentCamera
		if not cam then
			return Vector3.new()
		end
		local ray = cam:ScreenPointToRay(point2D.X, point2D.Y)
		return ray.Origin + ray.Direction * distance
	end

	local function update()
		if not running then
			return
		end

		local cam = Workspace.CurrentCamera
		if not cam or not part.Parent then
			return
		end

		local ok = pcall(function()
			local absPos = frame.AbsolutePosition
			local absSize = frame.AbsoluteSize

			local topLeft = absPos + Vector2.new(inset, inset)
			local topRight = topLeft + Vector2.new(math.max(absSize.X - inset * 2, 1), 0)
			local bottomRight = topLeft + Vector2.new(math.max(absSize.X - inset * 2, 1), math.max(absSize.Y - inset * 2, 1))

			local p1 = project(topLeft)
			local p2 = project(topRight)
			local p3 = project(bottomRight)

			local width = (p2 - p1).Magnitude
			local height = (p2 - p3).Magnitude

			part.CFrame = CFrame.fromMatrix((p1 + p3) / 2, cam.CFrame.XVector, cam.CFrame.YVector, cam.CFrame.ZVector)
			mesh.Scale = Vector3.new(width, height, 0)
		end)

		if not ok then
			part.Transparency = 1
		end
	end

	connections[#connections + 1] = RunService.RenderStepped:Connect(update)

	connections[#connections + 1] = screenGui:GetPropertyChangedSignal("Enabled"):Connect(function()
		part.Transparency = screenGui.Enabled and 0.98 or 1
	end)

	local function cleanup()
		running = false
		for _, connection in ipairs(connections) do
			pcall(function()
				connection:Disconnect()
			end)
		end
		if part then
			part:Destroy()
		end
	end

	frame.Destroying:Connect(cleanup)
	update()

	return part, cleanup
end

return {
	EnableAcrylicLighting = EnableAcrylicLighting,
	DisableAcrylicLighting = DisableAcrylicLighting,
	AttachAcrylicGlass = AttachAcrylicGlass,
}
end)()

