	end

	local textContainer = CreateInstance("Frame", {
		Name = "TextContainer",
		Parent = card,
		BackgroundTransparency = 1,
		Position = UDim2.new(0, textOffset, 0, 0),
		Size = UDim2.new(1, -textOffset, 0, 0),
