	CreateInstance("UICorner", {
		Parent = card,
		CornerRadius = UDim.new(0, 12),
	})

	local cardStroke = CreateInstance("UIStroke", {
		Parent = card,
		Color = self.Theme.Accent,
		Thickness = 1,
		Transparency = 1,
