	CreateInstance("UIPadding", {
		Parent = card,
		PaddingTop = UDim.new(0, 20),
		PaddingBottom = UDim.new(0, 20),
		PaddingLeft = UDim.new(0, 20),
		PaddingRight = UDim.new(0, 20),
	})

	local layout = CreateInstance("UIListLayout", {
		Parent = card,
		Padding = UDim.new(0, 14),
		SortOrder = Enum.SortOrder.LayoutOrder,
	})

	local titleLabel = CreateInstance("TextLabel", {
		Name = "Title",
		Parent = card,
		BackgroundTransparency = 1,
		TextTransparency = 1,
		Size = UDim2.new(1, 0, 0, 20),
		Font = Enum.Font.GothamBold,
		Text = config.Title or "Dialog",
		TextColor3 = self.Theme.TitleColor,
		TextSize = 17,
		TextXAlignment = Enum.TextXAlignment.Left,
		TextWrapped = true,
		LayoutOrder = 1,
	})
	table.insert(fadeEntries, { instance = titleLabel, prop = "TextTransparency", target = 0 })

	if config.Content and config.Content ~= "" then
		local contentLabel = CreateInstance("TextLabel", {
			Name = "Content",
			Parent = card,
			BackgroundTransparency = 1,
			TextTransparency = 1,
			Size = UDim2.new(1, 0, 0, 0),
			AutomaticSize = Enum.AutomaticSize.Y,
			Font = Enum.Font.Gotham,
			Text = config.Content,
			TextColor3 = self.Theme.DescColor,
			TextSize = 14,
			TextXAlignment = Enum.TextXAlignment.Left,
			TextWrapped = true,
			LayoutOrder = 2,
		})
		table.insert(fadeEntries, { instance = contentLabel, prop = "TextTransparency", target = 0 })
	end

	local buttons = config.Buttons or {}
	local buttonCount = math.max(#buttons, 1)

	local buttonsRow = CreateInstance("Frame", {
		Name = "Buttons",
		Parent = card,
		BackgroundTransparency = 1,
		Size = UDim2.new(1, 0, 0, 36),
		LayoutOrder = 3,
	})

	CreateInstance("UIListLayout", {
		Parent = buttonsRow,
		FillDirection = Enum.FillDirection.Horizontal,
		Padding = UDim.new(0, 10),
		SortOrder = Enum.SortOrder.LayoutOrder,
	})

	local dismissed = false
	local function close()
		if dismissed then
			return
		end
		dismissed = true

		local exitEntries = {}
		for _, entry in ipairs(fadeEntries) do
			table.insert(exitEntries, { instance = entry.instance, prop = entry.prop, target = 1 })
		end

		FadeTransparency(exitEntries, 0.18, Enum.EasingDirection.In)

		task.delay(0.18, function()
			backdrop:Destroy()
		end)
	end

	for index, buttonConfig in ipairs(buttons) do
		local buttonFrame = CreateInstance("TextButton", {
			Name = "Button" .. index,
			Parent = buttonsRow,
			Size = UDim2.new(1 / buttonCount, -8, 1, 0),
			BackgroundColor3 = self.Theme.Background,
			BackgroundTransparency = 1,
			Text = "",
			AutoButtonColor = false,
			LayoutOrder = index,
		})
		table.insert(fadeEntries, {
			instance = buttonFrame,
			prop = "BackgroundTransparency",
			target = 0,
		})

		CreateInstance("UICorner", {
			Parent = buttonFrame,
			CornerRadius = UDim.new(0, 6),
		})

		local btnStroke = CreateInstance("UIStroke", {
			Parent = buttonFrame,
			Color = self.Theme.Accent,
			Thickness = 1,
			Transparency = 1,
		})
		table.insert(fadeEntries, { instance = btnStroke, prop = "Transparency", target = 0.7 })

		local btnLabel = CreateInstance("TextLabel", {
			Parent = buttonFrame,
			BackgroundTransparency = 1,
			TextTransparency = 1,
			Size = UDim2.fromScale(1, 1),
			Font = Enum.Font.Gotham,
			Text = buttonConfig.Title or ("Button " .. index),
			TextColor3 = self.Theme.TitleColor,
			TextSize = 13,
		})
		table.insert(fadeEntries, { instance = btnLabel, prop = "TextTransparency", target = 0 })

		buttonFrame.MouseEnter:Connect(function()
			buttonFrame.BackgroundColor3 = self.Theme.Secondary
		end)

		buttonFrame.MouseLeave:Connect(function()
			buttonFrame.BackgroundColor3 = self.Theme.Background
		end)

		buttonFrame.MouseButton1Down:Connect(function()
			buttonFrame.BackgroundColor3 = self.Theme.Accent
		end)

		buttonFrame.MouseButton1Up:Connect(function()
			buttonFrame.BackgroundColor3 = self.Theme.Secondary
		end)

		buttonFrame.MouseButton1Click:Connect(function()
			if buttonConfig.Callback then
				local ok, err = pcall(buttonConfig.Callback)
				if not ok then
					warn("Vanta Dialog Callback Error: " .. tostring(err))
				end
			end
			close()
		end)
	end

	FadeTransparency(fadeEntries, 0.2, Enum.EasingDirection.Out)

	return {
		Frame = card,
		Close = close,
	}
end


return M
end)()

_modules["Config"] = (function()
local M = {}

local function HasFileIO()
	return typeof(writefile) == "function" and typeof(readfile) == "function"
end

function M:SaveConfig(fileName)
	fileName = fileName or "VantaConfig"

	if not HasFileIO() then
		self:Notify({
			Title = "Save Not Supported",
			Content = "This environment does not support file saving (writefile/readfile)",
			Duration = 5,
			icone = true,
		})
		return false
	end

	local data = {}
	for flag, element in pairs(self.Flags) do
		local ok, value = pcall(function()
			if element.GetString then
				return element.GetString()
			end
			if element.Get then
				local v = element:Get()
				if typeof(v) == "Color3" then
					return {
						__color = true,
						R = math.floor(v.R * 255 + 0.5),
						G = math.floor(v.G * 255 + 0.5),
						B = math.floor(v.B * 255 + 0.5),
					}
				end
				return v
			end
			return nil
		end)
		if ok and value ~= nil then
			data[flag] = value
		end
	end

	local ok2, json = pcall(function()
		return game:GetService("HttpService"):JSONEncode(data)
	end)

	if not ok2 then
		self:Notify({
			Title = "Save Error",
			Content = "Failed to encode settings",
			Duration = 5,
			icone = true,
		})
		return false
	end

	local ok3 = pcall(function()
		if not isfolder("VantaConfigs") then
			makefolder("VantaConfigs")
		end
		writefile("VantaConfigs/" .. fileName .. ".json", json)
	end)

	if not ok3 then
		self:Notify({
			Title = "Save Error",
			Content = "Failed to write file",
			Duration = 5,
			icone = true,
		})
		return false
	end

	self:Notify({
		Title = "Saved",
		Content = "Your settings were saved successfully",
		Duration = 3,
		icone = true,
	})
	return true
end

function M:LoadConfig(fileName)
	fileName = fileName or "VantaConfig"

	if not HasFileIO() then
		self:Notify({
			Title = "Load Not Supported",
			Content = "This environment does not support file reading",
			Duration = 5,
			icone = true,
		})
		return false
	end

	local ok, json = pcall(function()
		return readfile("VantaConfigs/" .. fileName .. ".json")
	end)

	if not ok or not json then
		self:Notify({
			Title = "No Saved Config",
			Content = 'No file found named "' .. fileName .. '"',
			Duration = 5,
			icone = true,
		})
		return false
	end

	local ok2, data = pcall(function()
		return game:GetService("HttpService"):JSONDecode(json)
	end)

	if not ok2 or type(data) ~= "table" then
		self:Notify({
			Title = "Load Error",
			Content = "Config file is corrupted or invalid",
			Duration = 5,
			icone = true,
		})
		return false
	end

	local loadedCount = 0
	for flag, value in pairs(data) do
		local element = self.Flags[flag]
		if element and element.Set then
			local ok3 = pcall(function()
				if typeof(value) == "table" and value.__color then
					element:Set(Color3.fromRGB(value.R, value.G, value.B))
				else
					element:Set(value)
				end
			end)
			if ok3 then
				loadedCount = loadedCount + 1
			end
		end
	end

	self:Notify({
		Title = "Loaded",
		Content = "Successfully loaded " .. loadedCount .. " setting(s)",
		Duration = 3,
		icone = true,
	})
	return true
end


return M
end)()

local function _init()
math.randomseed(tick())

local Library = {}
Library.__index = Library

local ThemeModule = _require("Theme")
local WindowMethods = _require("Window")(Library)
local NotifyMethods = _require("Notify")
local DialogMethods = _require("Dialog")
local ConfigMethods = _require("Config")

Library.Presets = ThemeModule.Presets

local function mix(methods)
	for name, fn in pairs(methods) do
		Library[name] = fn
	end
end

mix(WindowMethods)
mix(NotifyMethods)
mix(DialogMethods)
mix(ConfigMethods)

return Library
end

return _init()
